template:
{{css target}} { display: flex; flex-direction: column; gap: {{css params.gap}}; overflow: hidden; }
{{css target}} > * { flex-shrink: 0; animation: motion-marqueeVertical-{{css id}} {{css params.duration}}s linear infinite {{css params.direction}}; }
@keyframes motion-marqueeVertical-{{css id}} { from { transform: translateY(0) } to { transform: translateY(-100%) } }
